def build_faq_block(faq: list[tuple[str, str]]) -> str:
    lines = ["## Вопросы и ответы\n"]
    for question, answer in faq:
        lines.append(f"### {question}\n\n{answer}\n")
    return "\n".join(lines).strip() + "\n"


def build_article(article: Article) -> str:
    intro = textwrap.dedent(COMMON_INTRO).format(**article.__dict__).strip()
    body = textwrap.dedent(COMMON_BODY).format(**article.__dict__).strip()
    faq = build_faq_block(article.faq)
    content = f"""---
title: "{article.title}"
description: "{article.description}"
date: {article.date}
draft: false
---

# {article.title}

![{article.wagon_name}]({article.image})

{intro}

{body}

{faq}
"""
    return content


def main() -> None:
    BLOG_DIR.mkdir(parents=True, exist_ok=True)
    for article in ARTICLES:
        path = BLOG_DIR / f"{article.slug}.md"
        path.write_text(build_article(article), encoding="utf-8")


if __name__ == "__main__":
    main()
